import React, { useState } from "react";
import axios from "axios";

import MatchResults from "./MatchResults";

const JobForm = () => {
  const [jobData, setJobData] = useState({
    requiredSkills: "",
    minExperience: "",
  });

  const [results, setResults] = useState([]);

  const handleChange = (e) => {
    setJobData({
      ...jobData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      requiredSkills: jobData.requiredSkills.split(","),
      minExperience: Number(jobData.minExperience),
    };

    try {
      const response = await axios.post(
        "http://127.0.0.1:8000/api/match",
        payload,
      );

      setResults(response.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Job Requirements</h2>

      <form onSubmit={handleSubmit}>
        <input
          type="text"
          name="requiredSkills"
          placeholder="Required Skills"
          value={jobData.requiredSkills}
          onChange={handleChange}
        />

        <br />
        <br />

        <input
          type="number"
          name="minExperience"
          placeholder="Minimum Experience"
          value={jobData.minExperience}
          onChange={handleChange}
        />

        <br />
        <br />

        <button type="submit">Match Candidates</button>
      </form>

      <MatchResults results={results} />
    </div>
  );
};

export default JobForm;
